    // User badge data (would come from backend)
    userBadges: [],

    // Initialize badge system
    init() {
        this.loadUserBadges();
        this.startProgressTracking();
    },

    // Load user's earned badges
    loadUserBadges() {
        // Simulated - would fetch from API
        this.userBadges = JSON.parse(localStorage.getItem('trenches_badges') || '[]');
    },

    // Check if user has badge
    hasBadge(badgeId) {
        return this.userBadges.includes(badgeId);
    },

    // Unlock a badge
    async unlockBadge(badgeId) {
        if (this.hasBadge(badgeId)) return;

        const badge = this.badges[badgeId];
        if (!badge) return;

        // Add to user's badges
        this.userBadges.push(badgeId);
        localStorage.setItem('trenches_badges', JSON.stringify(this.userBadges));

        // Show unlock animation
        this.showBadgeUnlock(badge);

        // Trigger confetti
        this.triggerConfetti();

        // Show toast notification
        this.showBadgeToast(badge);

        // Update UI
        this.updateBadgeUI();

        // Analytics/event tracking
        this.trackBadgeUnlock(badge);
    },

    // Show badge unlock modal
    showBadgeUnlock(badge) {
        const modal = document.getElementById('badge-modal');
        const display = document.getElementById('unlocked-badge-display');

        display.innerHTML = `
            <span class="badge-emoji">${badge.emoji}</span>
            <span class="badge-name">${badge.name}</span>
            <span class="badge-rarity ${badge.rarity}">${badge.rarity}</span>
        `;

        display.parentElement.querySelector('.unlock-description').textContent = badge.description;

        modal.classList.add('active');

        // Play sound effect (optional)
        this.playUnlockSound(badge.rarity);
    },

    // Close badge modal
    closeBadgeModal() {
        document.getElementById('badge-modal').classList.remove('active');
    },

    // Trigger confetti animation
    triggerConfetti() {
        const container = document.getElementById('confetti-container');
        const colors = ['#00ff9d', '#00d4ff', '#a855f7', '#ff006e', '#ffd700', '#ff6b35'];
        const shapes = ['square', 'circle', 'triangle'];

        for (let i = 0; i < 100; i++) {
            const confetti = document.createElement('div');
            confetti.className = `confetti ${shapes[Math.floor(Math.random() * shapes.length)]}`;
            confetti.style.left = Math.random() * 100 + '%';
            confetti.style.backgroundColor = colors[Math.floor(Math.random() * colors.length)];
            confetti.style.borderBottomColor = colors[Math.floor(Math.random() * colors.length)];
            confetti.style.animationDelay = Math.random() * 2 + 's';
            confetti.style.animationDuration = (Math.random() * 2 + 2) + 's';
            container.appendChild(confetti);

            // Remove after animation
            setTimeout(() => confetti.remove(), 4000);
        }
    },

    // Show badge toast notification
    showBadgeToast(badge) {
        const container = document.getElementById('toast-container');
        const toast = document.createElement('div');
        toast.className = `toast badge-toast ${badge.rarity}`;
        toast.innerHTML = `
            <div class="badge-toast-icon">${badge.emoji}</div>
            <div class="badge-toast-content">
                <div class="badge-toast-title">Badge Unlocked!</div>
                <div class="badge-toast-name">${badge.name}</div>
                <div class="badge-toast-rarity" style="color: var(--badge-${badge.rarity})">${badge.rarity}</div>
            </div>
        `;

        container.appendChild(toast);

        // Remove after delay
        setTimeout(() => {
            toast.style.animation = 'slideIn 0.3s ease reverse';
            setTimeout(() => toast.remove(), 300);
        }, 5000);
    },

    // Play unlock sound based on rarity
    playUnlockSound(rarity) {
        // Web Audio API for simple beep/boop sounds
        const audioContext = new (window.AudioContext || window.webkitAudioContext)();
        const oscillator = audioContext.createOscillator();
        const gainNode = audioContext.createGain();

        oscillator.connect(gainNode);
        gainNode.connect(audioContext.destination);

        // Different sounds for different rarities
        const frequencies = {
            common: 440,
            uncommon: 554,
            rare: 659,
            epic: 880,
            legendary: 1108
        };

        oscillator.frequency.value = frequencies[rarity] || 440;
        gainNode.gain.setValueAtTime(0.3, audioContext.currentTime);
        gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.5);

        oscillator.start(audioContext.currentTime);
        oscillator.stop(audioContext.currentTime + 0.5);
    },

    // Check progress and unlock badges
    checkProgress(userStats) {
        Object.values(this.badges).forEach(badge => {
            if (this.hasBadge(badge.id)) return;

            const shouldUnlock = this.checkCondition(badge.condition, userStats);
            if (shouldUnlock) {
                this.unlockBadge(badge.id);
            }
        });
    },

    // Check if condition is met
    checkCondition(condition, stats) {
        switch (condition.type) {
            case 'post_count':
                return (stats.posts || 0) >= condition.value;
            case 'comment_count':
                return (stats.comments || 0) >= condition.value;
            case 'streak':
                return (stats.streak || 0) >= condition.value;
            case 'wallet_connect':
                return stats.walletConnected;
            case 'verified_alpha':
                return (stats.verifiedAlpha || 0) >= condition.value;
            case 'follower_count':
                return (stats.followers || 0) >= condition.value;
            case 'total_upvotes':
                return (stats.totalUpvotes || 0) >= condition.value;
            case 'single_post_upvotes':
                return (stats.maxPostUpvotes || 0) >= condition.value;
            case 'portfolio_value':
                return (stats.portfolioValue || 0) >= condition.value;
            default:
                return false;
        }
    },

    // Start tracking user progress
    startProgressTracking() {
        // Track various user actions
        this.trackAction = this.trackAction.bind(this);

        // Example: Track post creation
        document.addEventListener('postCreated', () => {
            this.trackAction('post');
        });

        // Example: Track comment
        document.addEventListener('commentCreated', () => {
            this.trackAction('comment');
        });
    },

    // Track user action
    trackAction(action) {
        const stats = JSON.parse(localStorage.getItem('trenches_stats') || '{}');

        switch (action) {
            case 'post':
                stats.posts = (stats.posts || 0) + 1;
                break;
            case 'comment':
                stats.comments = (stats.comments || 0) + 1;
                break;
            case 'upvote':
                stats.totalUpvotes = (stats.totalUpvotes || 0) + 1;
                break;
        }

        localStorage.setItem('trenches_stats', JSON.stringify(stats));
        this.checkProgress(stats);
    },

    // Update badge UI elements
    updateBadgeUI() {
        // Update badge count in header
        const badgeCountEl = document.querySelector('.badge-count');
        if (badgeCountEl) {
            badgeCountEl.textContent = this.userBadges.length;
        }
    },

    // Track badge unlock for analytics
    trackBadgeUnlock(badge) {
        // Send to analytics
        console.log('Badge unlocked:', badge.name);
        // gtag('event', 'badge_unlock', { badge_id: badge.id, rarity: badge.rarity });
    },

    // Get badge progress percentage
    getProgress(badgeId, stats) {
        const badge = this.badges[badgeId];
        if (!badge) return 0;

        const current = stats[badge.condition.type] || 0;
        const target = badge.condition.value;

        if (typeof target === 'object') {
            // Complex condition (like alpha_king)
            return Math.min(100, (current / Object.values(target)[0]) * 100);
        }

        return Math.min(100, (current / target) * 100);
    },

    // Get next badge to unlock
    getNextBadge(stats) {
        const lockedBadges = Object.values(this.badges)
            .filter(b => !this.hasBadge(b.id) && !b.hidden)
            .sort((a, b) => {
                const progressA = this.getProgress(a.id, stats);
                const progressB = this.getProgress(b.id, stats);
                return progressB - progressA;
            });

        return lockedBadges[0] || null;
    }
};

// Initialize on load
document.addEventListener('DOMContentLoaded', () => {
    BadgeSystem.init();
});

// Close modal on click outside
document.getElementById('badge-modal')?.addEventListener('click', (e) => {
    if (e.target.id === 'badge-modal') {
        BadgeSystem.closeBadgeModal();
    }
});
"}

