 * The Trenches - Main JavaScript
 */

// Modal Functions
function openCreateModal(type = 'text') {
    const modal = document.getElementById('create-modal');
    modal.classList.add('active');

    // Set post type
    document.querySelectorAll('.post-type-btn').forEach(btn => {
        btn.classList.remove('active');
        if (btn.dataset.type === type) {
            btn.classList.add('active');
        }
    });
}

function closeCreateModal() {
    document.getElementById('create-modal').classList.remove('active');
}

function closeBadgeModal() {
    document.getElementById('badge-modal').classList.remove('active');
}

// Vote Function
function vote(btn, direction) {
    const voteContainer = btn.parentElement;
    const upvoteBtn = voteContainer.querySelector('.upvote');
    const downvoteBtn = voteContainer.querySelector('.downvote');
    const countEl = voteContainer.querySelector('.vote-count');
    let count = parseInt(countEl.textContent.replace(/,/g, ''));

    // Remove active states
    upvoteBtn.classList.remove('active');
    downvoteBtn.classList.remove('active');

    if (direction === 1) {
        if (btn.classList.contains('active')) {
            count--;
        } else {
            count++;
            upvoteBtn.classList.add('active');
        }
    } else {
        if (btn.classList.contains('active')) {
            count++;
        } else {
            count--;
            downvoteBtn.classList.add('active');
        }
    }

    countEl.textContent = count.toLocaleString();

    // Track for badges
    if (window.BadgeSystem && direction === 1) {
        BadgeSystem.trackAction('upvote');
    }
}

// Submit Post
function submitPost() {
    const board = document.querySelector('.board-select').value;
    const title = document.querySelector('.post-title-input').value;
    const body = document.querySelector('.post-body').value;

    if (!board || !title) {
        showToast('Please fill in all required fields', 'error');
        return;
    }

    // Simulate post creation
    showToast('Post created successfully!', 'success');
    closeCreateModal();

    // Track for badges
    if (window.BadgeSystem) {
        BadgeSystem.trackAction('post');
    }

    // Clear form
    document.querySelector('.board-select').value = '';
    document.querySelector('.post-title-input').value = '';
    document.querySelector('.post-body').value = '';
}

// Toast Notifications
function showToast(message, type = 'info') {
    const container = document.getElementById('toast-container');
    const toast = document.createElement('div');
    toast.className = `toast ${type}`;

    const icons = {
        success: '✅',
        error: '❌',
        info: 'ℹ️',
        warning: '⚠️'
    };

    toast.innerHTML = `
        <span class="toast-icon">${icons[type]}</span>
        <span class="toast-message">${message}</span>
    `;

    container.appendChild(toast);

    setTimeout(() => {
        toast.style.animation = 'slideIn 0.3s ease reverse';
        setTimeout(() => toast.remove(), 300);
    }, 3000);
}

// Post Type Selector
document.querySelectorAll('.post-type-btn').forEach(btn => {
    btn.addEventListener('click', () => {
        document.querySelectorAll('.post-type-btn').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
    });
});

// Sort Tabs
document.querySelectorAll('.sort-tab').forEach(tab => {
    tab.addEventListener('click', () => {
        document.querySelectorAll('.sort-tab').forEach(t => t.classList.remove('active'));
        tab.classList.add('active');
    });
});

// Alert Banner Close
document.querySelector('.alert-close')?.addEventListener('click', function() {
    this.parentElement.style.display = 'none';
});

// Sentiment Selection
document.querySelectorAll('.sentiment-item').forEach(item => {
    item.addEventListener('click', () => {
        document.querySelectorAll('.sentiment-item').forEach(i => i.classList.remove('active'));
        item.classList.add('active');
    });
});

// Simulate Live Activity Updates
function updateLiveActivity() {
    const activities = [
        { icon: '🐋', text: 'Whale bought 500 ETH', time: 'now' },
        { icon: '🔥', text: 'New alpha in Alpha Central', time: '1m' },
        { icon: '💎', text: '@CryptoKing earned Diamond Hands', time: '2m' },
        { icon: '🚨', text: 'Scam alert: FakeToken', time: '3m' },
        { icon: '🚀', text: '$PEPE up 25%', time: '5m' },
        { icon: '🎯', text: 'Prediction resolved: Correct!', time: '6m' }
    ];

    const feed = document.querySelector('.live-feed');
    if (feed) {
        const random = activities[Math.floor(Math.random() * activities.length)];
        const item = document.createElement('div');
        item.className = 'live-item';
        item.innerHTML = `
            <span class="live-icon">${random.icon}</span>
            <span class="live-text">${random.text}</span>
            <span class="live-time">${random.time}</span>
        `;

        feed.insertBefore(item, feed.firstChild);
        if (feed.children.length > 4) {
            feed.lastChild.remove();
        }
    }
}

// Update live activity every 10 seconds
setInterval(updateLiveActivity, 10000);

// Keyboard Shortcuts
document.addEventListener('keydown', (e) => {
    // Cmd/Ctrl + K for search
    if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        document.querySelector('.nav-search input').focus();
    }

    // Escape to close modals
    if (e.key === 'Escape') {
        closeCreateModal();
        closeBadgeModal();
    }

    // Cmd/Ctrl + Enter to submit post
    if ((e.metaKey || e.ctrlKey) && e.key === 'Enter' && document.getElementById('create-modal').classList.contains('active')) {
        submitPost();
    }
});

// Infinite Scroll Simulation
let loading = false;
window.addEventListener('scroll', () => {
    if (loading) return;

    const scrollPosition = window.innerHeight + window.scrollY;
    const bodyHeight = document.body.offsetHeight;

    if (scrollPosition >= bodyHeight - 500) {
        loading = true;

        const loadMoreBtn = document.querySelector('.load-more');
        if (loadMoreBtn) {
            loadMoreBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i><span>Loading...</span>';

            setTimeout(() => {
                loadMoreBtn.innerHTML = '<i class="fas fa-spinner"></i><span>Load More</span>';
                loading = false;
                showToast('More posts loaded!', 'success');
            }, 1500);
        }
    }
});

// Simulate Badge Unlock (for demo)
function simulateBadgeUnlock() {
    const badges = [
        { id: 'first_post', name: 'First Blood', emoji: '🎯', rarity: 'common' },
        { id: 'seven_day_streak', name: 'Week Warrior', emoji: '🔥🔥', rarity: 'uncommon' },
        { id: 'alpha_caller', name: 'Alpha Caller', emoji: '🎯', rarity: 'rare' },
        { id: 'fud_lord', name: 'FUD Lord', emoji: '🧌', rarity: 'legendary' }
