{"path": "/root/rmi/frontend/the-trenches/css/animations.css", "content": "/* The Trenches - Animations */

/* Page Load Animations */
@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
}

@keyframes scaleIn {
    from {
        opacity: 0;
        transform: scale(0.9);
    }
    to {
        opacity: 1;
        transform: scale(1);
    }
}

@keyframes slideInLeft {
    from {
        opacity: 0;
        transform: translateX(-20px);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}

@keyframes slideInRight {
    from {
        opacity: 0;
        transform: translateX(20px);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}

/* Apply animations to elements */
.post-card {
    animation: fadeInUp 0.4s ease forwards;
}

.post-card:nth-child(1) { animation-delay: 0.05s; }
.post-card:nth-child(2) { animation-delay: 0.1s; }
.post-card:nth-child(3) { animation-delay: 0.15s; }
.post-card:nth-child(4) { animation-delay: 0.2s; }
.post-card:nth-child(5) { animation-delay: 0.25s; }

.widget {
    animation: fadeInUp 0.5s ease forwards;
}

.sidebar-section {
    animation: slideInLeft 0.4s ease forwards;
}

/* Hover Effects */
.post-card {
    transition: transform 0.2s, box-shadow 0.2s, border-color 0.2s;
}

.post-card:hover {
    transform: translateY(-2px);
}

/* Button Animations */
.btn-primary, .btn-create {
    position: relative;
    overflow: hidden;
}

.btn-primary::after, .btn-create::after {
    content: '';
    position: absolute;
    top: 50%;
    left: 50%;
    width: 0;
    height: 0;
    background: rgba(255, 255, 255, 0.2);
    border-radius: 50%;
    transform: translate(-50%, -50%);
    transition: width 0.3s, height 0.3s;
}

.btn-primary:active::after, .btn-create:active::after {
    width: 200px;
    height: 200px;
}

/* Vote Button Animations */
.vote-btn {
    transition: all 0.15s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

.vote-btn:active {
    transform: scale(0.85);
}

.vote-btn.upvote.active {
    animation: upvote-bounce 0.4s ease;
}

.vote-btn.downvote.active {
    animation: downvote-bounce 0.4s ease;
}

@keyframes upvote-bounce {
    0% { transform: scale(1); }
    50% { transform: scale(1.3); }
    100% { transform: scale(1); }
}

@keyframes downvote-bounce {
    0% { transform: scale(1); }
    50% { transform: scale(1.3); }
    100% { transform: scale(1); }
}

/* Live Indicator Pulse */
.alert-badge, .live-indicator {
    animation: live-pulse 2s infinite;
}

@keyframes live-pulse {
    0%, 100% { 
        opacity: 1;
        box-shadow: 0 0 0 0 rgba(255, 71, 87, 0.7);
    }
    50% { 
        opacity: 0.8;
        box-shadow: 0 0 0 8px rgba(255, 71, 87, 0);
    }
}

/* Loading Spinner */
@keyframes spin {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
}

.fa-spinner {
    animation: spin 1s linear infinite;
}

/* Streak Fire Animation */
.streak-icon {
    animation: fire-flicker 1.5s infinite;
}

@keyframes fire-flicker {
    0%, 100% { 
        transform: scale(1);
        filter: brightness(1);
    }
    25% { 
        transform: scale(1.1) rotate(-5deg);
        filter: brightness(1.2);
    }
    50% { 
        transform: scale(0.95) rotate(5deg);
        filter: brightness(0.9);
    }
    75% { 
        transform: scale(1.05) rotate(-3deg);
        filter: brightness(1.1);
    }
}

/* Notification Badge Bounce */
.notification-badge {
    animation: badge-bounce 0.5s ease;
}

@keyframes badge-bounce {
    0%, 100% { transform: scale(1); }
    50% { transform: scale(1.3); }
}

/* Card Glow Effects */
.alpha-post:hover {
    box-shadow: 0 0 30px rgba(0, 255, 157, 0.15);
}

.scam-post:hover {
    box-shadow: 0 0 30px rgba(255, 71, 87, 0.15);
}

.meme-post:hover {
    box-shadow: 0 0 30px rgba(168, 85, 247, 0.15);
}

/* Avatar Hover */
.author-avatar, .avatar {
    transition: transform 0.2s, border-color 0.2s;
}

.author-avatar:hover, .avatar:hover {
    transform: scale(1.1);
}

/* Tag Animations */
.post-tag {
    transition: all 0.2s;
}

.post-card:hover .post-tag {
    transform: translateY(-1px);
}

/* Modal Animations */
.modal {
    transition: opacity 0.3s ease;
}

.modal-content {
    animation: modal-pop 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

@keyframes modal-pop {
    from {
        opacity: 0;
        transform: scale(0.9) translateY(20px);
    }
    to {
        opacity: 1;
        transform: scale(1) translateY(0);
    }
}

/* Nav Link Underline Effect */
.nav-links li a {
    position: relative;
}

.nav-links li a::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 20px;
    right: 20px;
    height: 2px;
    background: var(--accent-primary);
    transform: scaleX(0);
    transition: transform 0.2s;
}

.nav-links li a:hover::after,
.nav-links li.active a::after {
    transform: scaleX(1);
}

/* Search Focus Animation */
.nav-search input {
    transition: all 0.2s;
}

.nav-search input:focus {
    transform: scale(1.02);
}

/* Create Options Hover */
.create-option {
    transition: all 0.2s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

.create-option:hover {
    transform: translateY(-4px) scale(1.02);
}

.create-option:active {
    transform: translateY(-2px) scale(0.98);
}

/* Trending Items Stagger */
.trending-list li {
    opacity: 0;
    animation: slideInRight 0.3s ease forwards;
}

.trending-list li:nth-child(1) { animation-delay: 0.1s; }
.trending-list li:nth-child(2) { animation-delay: 0.15s; }
.trending-list li:nth-child(3) { animation-delay: 0.2s; }
.trending-list li:nth-child(4) { animation-delay: 0.25s; }
.trending-list li:nth-child(5) { animation-delay: 0.3s; }

/* Live Feed Animation */
.live-item {
    animation: live-slide 0.3s ease;
}

@keyframes live-slide {
    from {
        opacity: 0;
        transform: translateX(-10px);
    }
    to {
        opacity: 1;
        transform: translateX(0);
    }
}

/* Leaderboard Animation */
.leaderboard-item {
    transition: all 0.2s;
}

.leaderboard-item:hover {
    transform: translateX(5px);
    background: var(--bg-hover);
    border-radius: var(--radius-md);
    padding-left: 10px;
}

/* Progress Bar Animation */
.streak-fill, .collection-progress-fill {
    transition: width 1s cubic-bezier(0.4, 0, 0.2, 1);
}

/* Sentiment Bar Selection */
.sentiment-item {
    transition: all 0.2s;
}

.sentiment-item:hover {
    transform: translateY(-2px);
}

.sentiment-item.active {
    animation: sentiment-pulse 0.5s ease;
}

@keyframes sentiment-pulse {
    0%, 100% { transform: scale(1); }
    50% { transform: scale(1.05); }
}

/* Meme Container Hover */
.meme-container {
    overflow: hidden;
    border-radius: var(--radius-md);
}

.meme-container img {
    transition: transform 0.3s;
}

.meme-container:hover img {
    transform: scale(1.02);
}

/* Loss Porn Glitch Effect */
.loss-screenshot {
    position: relative;
}

.loss-screenshot::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: repeating-linear-gradient(
        0deg,
        transparent,
        transparent 2px,
        rgba(255, 71, 87, 0.03) 2px,
        rgba(255, 71, 87, 0.03) 4px
    );
    pointer-events: none;
}

/* Award Glow */
.award {
    animation: award-glow 2s infinite;
}

@keyframes award-glow {
    0%, 100% { filter: brightness(1); }
    50% { filter: brightness(1.3); }
}

/* Scroll Reveal */
.reveal {
    opacity: 0;
    transform: translateY(30px);
    transition: all 0.6s ease;
}

.reveal.active {
    opacity: 1;
    transform: translateY(0);
}

/* Skeleton Loading */
.skeleton {
    background: linear-gradient(
        90deg,
        var(--bg-tertiary) 25%,
        var(--bg-hover) 50%,
        var(--bg-tertiary) 75%
    );
    background-size: 200% 100%;
    animation: skeleton-loading 1.5s infinite;
}

@keyframes skeleton-loading {
    0% { background-position: 200% 0; }
    100% { background-position: -200% 0; }
}

/* Floating Animation for Icons */
.float {
    animation: float 3s ease-in-out infinite;
}

@keyframes float {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-10px); }
}

/* Shake Animation for Errors */
.shake {
    animation: shake 0.5s ease;
}

@keyframes shake {
    0%, 100% { transform: translateX(0); }
    10%, 30%, 50%, 70%, 90% { transform: translateX(-5px); }
    20%, 40%, 60%, 80% { transform: translateX(5px); }
}

/* Pulse Ring for Notifications */
.pulse-ring {
    position: absolute;
    border-radius: 50%;
    animation: pulse-ring 1.5s cubic-bezier(0.215, 0.61, 0.355, 1) infinite;
}

@keyframes pulse-ring {
    0% {
        transform: scale(0.33);
        opacity: 1;
    }
    80%, 100% {
        transform: scale(2);
        opacity: 0;
    }
}

/* Gradient Text Animation */
.gradient-text {
    background: linear-gradient(
        90deg,
        var(--accent-primary),
        var(--accent-secondary),
        var(--accent-primary)
    );
    background-size: 200% auto;
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    animation: gradient-shift 3s linear infinite;
}

@keyframes gradient-shift {
    0% { background-position: 0% center; }
    100% { background-position: 200% center; }
}

/* Glow Effect for Legendary Items */
.legendary-glow {
    animation: legendary-glow 2s ease-in-out infinite;
}

@keyframes legendary-glow {
    0%, 100% {
        box-shadow: 0 0 5px rgba(245, 158, 11, 0.5),
                    0 0 10px rgba(245, 158, 11, 0.3),
                    0 0 15px rgba(245, 158, 11, 0.1);
    }
    50% {
        box-shadow: 0 0 10px rgba(245, 158, 11, 0.8),
                    0 0 20px rgba(245, 158, 11, 0.5),
                    0 0 30px rgba(245, 158, 11, 0.3);
    }
}

/* Typewriter Effect */
.typewriter {
    overflow: hidden;
    white-space: nowrap;
    animation: typing 3s steps(40, end);
}

@keyframes typing {
    from { width: 0; }
    to { width: 100%; }
}

/* Heart Beat for Like Button */
.heart-beat {
    animation: heart-beat 0.3s ease;
}

@keyframes heart-beat {
    0% { transform: scale(1); }
    25% { transform: scale(1.2); }
    50% { transform: scale(0.95); }
    100% { transform: scale(1); }
}

/* Ripple Effect */
.ripple {
    position: relative;
    overflow: hidden;
}

.ripple::after {
    content: '';
    position: absolute;
    width: 100%;
    height: 100%;
    top: 0;
    left: 0;
    pointer-events: none;
    background-image: radial-gradient(circle, rgba(255, 255, 255, 0.3) 10%, transparent 10.01%);
    background-repeat: no-repeat;
    background-position: 50%;
    transform: scale(10, 10);
    opacity: 0;
    transition: transform 0.5s, opacity 1s;
}

.ripple:active::after {
    transform: scale(0, 0);
    opacity: 0.3;
    transition: 0s;
}
"}

