Fixed API Service - Corrected implementations for Helius, Arkham, and Groq
"""
import httpx
import asyncio
import hmac
import hashlib
import time
from typing import List, Dict, Any, Optional
from datetime import datetime
from config.settings import settings
import logging

logger = logging.getLogger(__name__)

class FixedAPIService:
    """Service with corrected API implementations"""

    def __init__(self):
        self.helius_key = settings.HELIUS_API_KEY
        self.arkham_key = settings.ARKHAM_API_KEY
        self.groq_key = settings.GROQ_API_KEY

    # ==========================================
    # HELIUS (SOLANA) - FIXED
    # ==========================================

    async def get_solana_wallet_data(self, address: str) -> Dict[str, Any]:
        """Get Solana wallet data from Helius"""
        if not self.helius_key:
            return {"error": "Helius API key not configured"}

        try:
            async with httpx.AsyncClient() as client:
                # Get balances
                balance_url = f"https://api.helius.xyz/v0/addresses/{address}/balances"
                balance_resp = await client.get(
                    balance_url, 
                    params={"api-key": self.helius_key},
                    timeout=30.0
                )
                balance_data = balance_resp.json() if balance_resp.status_code == 200 else {}

                # Get transactions
                tx_url = f"https://api.helius.xyz/v0/addresses/{address}/transactions"
                tx_resp = await client.get(
                    tx_url,
                    params={"api-key": self.helius_key, "limit": 100},
                    timeout=30.0
                )
                tx_data = tx_resp.json() if tx_resp.status_code == 200 else []

                return {
                    "success": True,
                    "address": address,
                    "chain": "solana",
                    "balance": balance_data,
                    "transactions": tx_data[:100],
                    "transaction_count": len(tx_data),
                    "analyzed_at": datetime.utcnow().isoformat()
                }
        except Exception as e:
            logger.error(f"Helius error: {e}")
            return {"error": str(e), "address": address}

    # ==========================================
    # ARKHAM (ETHEREUM) - FIXED WITH PROPER AUTH
    # ==========================================

    def _arkham_sign_request(self, timestamp: str) -> str:
        """Generate Arkham API signature"""
        message = f"{timestamp}GET"
        signature = hmac.new(
            self.arkham_key.encode(),
            message.encode(),
            hashlib.sha256
        ).hexdigest()
        return signature

    async def get_ethereum_wallet_data(self, address: str) -> Dict[str, Any]:
        """Get Ethereum wallet data from Arkham with proper auth"""
        if not self.arkham_key:
            return {"error": "Arkham API key not configured"}

        timestamp = str(int(time.time() * 1000))
        signature = self._arkham_sign_request(timestamp)

        headers = {
            "X-API-Key": self.arkham_key,
            "X-Timestamp": timestamp,
            "X-Signature": signature
        }

        try:
            async with httpx.AsyncClient() as client:
                # Get portfolio
                url = f"https://api.arkhamintelligence.com/intelligence/address/{address}"
                resp = await client.get(url, headers=headers, timeout=30.0)

                if resp.status_code == 200:
                    data = resp.json()
                    return {
                        "success": True,
                        "address": address,
                        "chain": "ethereum",
                        "data": data,
                        "analyzed_at": datetime.utcnow().isoformat()
                    }
                else:
                    return {
                        "error": f"Arkham API error: {resp.status_code}",
                        "message": resp.text[:200]
                    }
        except Exception as e:
            logger.error(f"Arkham error: {e}")
            return {"error": str(e), "address": address}

    # ==========================================
    # GROQ (LLM) - FIXED
    # ==========================================

    async def groq_chat_completion(self, messages: List[Dict], model: str = "llama-3.1-8b-instant") -> Dict[str, Any]:
        """Get chat completion from Groq"""
        if not self.groq_key:
            return {"error": "Groq API key not configured"}

        url = "https://api.groq.com/openai/v1/chat/completions"
        headers = {
            "Authorization": f"Bearer {self.groq_key}",
            "Content-Type": "application/json"
        }
        payload = {
            "model": model,
            "messages": messages,
            "temperature": 0.7,
            "max_tokens": 1024
        }

        try:
            async with httpx.AsyncClient() as client:
                resp = await client.post(url, headers=headers, json=payload, timeout=60.0)

                if resp.status_code == 200:
                    return {"success": True, "data": resp.json()}
                else:
                    return {
                        "error": f"Groq API error: {resp.status_code}",
                        "message": resp.text[:300]
                    }
        except Exception as e:
            logger.error(f"Groq error: {e}")
            return {"error": str(e)}

    # ==========================================
    # TEST ALL APIs
    # ==========================================

    async def test_all_apis(self) -> Dict[str, Any]:
        """Test all API connections"""
        results = {}

        # Test Helius with a known Solana address (Solana Foundation)
        solana_test_addr = "SeedHQPwVFfV6b6UQ9sPpP4f5qT1z1v9F1z9F1z9F1z"
        results["helius"] = await self.get_solana_wallet_data(solana_test_addr)

        # Test Arkham with a known ETH address (Vitalik)
        eth_test_addr = "0xd8dA6BF26964aF9D7eEd9e03E53415D37aA96045"
        results["arkham"] = await self.get_ethereum_wallet_data(eth_test_addr)

        # Test Groq
        results["groq"] = await self.groq_chat_completion([
            {"role": "user", "content": "Say 'API test successful'"}
        ])

        return results


# Standalone test
if __name__ == "__main__":
    import asyncio

    async def main():
        service = FixedAPIService()
        results = await service.test_all_apis()

        for name, result in results.items():
            print(f"\n{name.upper()}:")
            if "error" in result:
                print(f"  ❌ ERROR: {result['error']}")
            else:
                print(f"  ✅ SUCCESS")
                if "data" in result:
                    print(f"  Response keys: {list(result['data'].keys())[:5]}")

    asyncio.run(main())
