{"path": "/root/rmi/backend/database/postgres_client.py", "content": """"
PostgreSQL Client - Supabase-compatible wrapper for local PostgreSQL
"""
import psycopg2
import psycopg2.extras
import json
from typing import List, Dict, Any, Optional
from contextlib import contextmanager
import logging

logger = logging.getLogger(__name__)

class PostgresClient:
    """PostgreSQL client that mimics Supabase API"""

    def __init__(self, database_url: str):
        self.database_url = database_url

    @contextmanager
    def _get_connection(self):
        """Get database connection"""
        conn = psycopg2.connect(self.database_url)
        try:
            yield conn
        finally:
            conn.close()

    def table(self, name: str):
        """Return a table query builder"""
        return PostgresTable(self, name)

    def rpc(self, function_name: str, params: dict = None):
        """Call a stored procedure"""
        return PostgresRPC(self, function_name, params)


class PostgresTable:
    """Query builder for PostgreSQL tables"""

    def __init__(self, client: PostgresClient, table_name: str):
        self.client = client
        self.table_name = table_name
        self._select = "*"
        self._where = []
        self._order = None
        self._limit = None
        self._range = None

    def select(self, columns: str = "*"):
        """Select columns"""
        self._select = columns
        return self

    def insert(self, data: dict):
        """Insert data"""
        return PostgresInsert(self.client, self.table_name, data)

    def update(self, data: dict):
        """Update data"""
        return PostgresUpdate(self.client, self.table_name, data, self._where)

    def delete(self):
        """Delete rows"""
        return PostgresDelete(self.client, self.table_name, self._where)

    def upsert(self, data: dict):
        """Upsert data"""
        return PostgresUpsert(self.client, self.table_name, data)

    # WHERE clauses
    def eq(self, column: str, value):
        self._where.append(("eq", column, value))
        return self

    def neq(self, column: str, value):
        self._where.append(("neq", column, value))
        return self

    def gt(self, column: str, value):
        self._where.append(("gt", column, value))
        return self

    def gte(self, column: str, value):
        self._where.append(("gte", column, value))
        return self

    def lt(self, column: str, value):
        self._where.append(("lt", column, value))
        return self

    def lte(self, column: str, value):
        self._where.append(("lte", column, value))
        return self

    def is_(self, column: str, value):
        self._where.append(("is", column, value))
        return self

    def in_(self, column: str, values: list):
        self._where.append(("in", column, values))
        return self

    def like(self, column: str, pattern: str):
        self._where.append(("like", column, pattern))
        return self

    def ilike(self, column: str, pattern: str):
        self._where.append(("ilike", column, pattern))
        return self

    # Ordering and pagination
    def order(self, column: str, desc: bool = False):
        self._order = (column, "DESC" if desc else "ASC")
        return self

    def limit(self, count: int):
        self._limit = count
        return self

    def range(self, start: int, end: int):
        self._range = (start, end - start + 1)
        return self

    def single(self):
        self._limit = 1
        return self

    def _build_query(self):
        """Build SQL query"""
        query = f"SELECT {self._select} FROM {self.table_name}"
        params = []

        # WHERE clauses
        if self._where:
            conditions = []
            for op, col, val in self._where:
                if op == "eq":
                    conditions.append(f"{col} = %s")
                    params.append(val)
                elif op == "neq":
                    conditions.append(f"{col} != %s")
                    params.append(val)
                elif op == "gt":
                    conditions.append(f"{col} > %s")
                    params.append(val)
                elif op == "gte":
                    conditions.append(f"{col} >= %s")
                    params.append(val)
                elif op == "lt":
                    conditions.append(f"{col} < %s")
                    params.append(val)
                elif op == "lte":
                    conditions.append(f"{col} <= %s")
                    params.append(val)
                elif op == "is":
                    conditions.append(f"{col} IS %s")
                    params.append(val)
                elif op == "in":
                    placeholders = ",".join(["%s"] * len(val))
                    conditions.append(f"{col} IN ({placeholders})")
                    params.extend(val)
                elif op == "like":
                    conditions.append(f"{col} LIKE %s")
                    params.append(val)
                elif op == "ilike":
                    conditions.append(f"{col} ILIKE %s")
                    params.append(val)
            query += " WHERE " + " AND ".join(conditions)

        # ORDER BY
        if self._order:
            query += f" ORDER BY {self._order[0]} {self._order[1]}"

        # LIMIT/OFFSET
        if self._range:
            query += f" LIMIT %s OFFSET %s"
            params.extend([self._range[1], self._range[0]])
        elif self._limit:
            query += f" LIMIT %s"
            params.append(self._limit)

        return query, params

    def execute(self):
        """Execute query"""
        query, params = self._build_query()

        with self.client._get_connection() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, params)
                rows = cur.fetchall()

                class Result:
                    def __init__(self, data):
                        self.data = [dict(row) for row in data]
                        self.count = len(data)

                return Result(rows)


class PostgresInsert:
    """Insert query builder"""

    def __init__(self, client: PostgresClient, table_name: str, data: dict):
        self.client = client
        self.table_name = table_name
        self.data = data

    def execute(self):
        columns = ", ".join(self.data.keys())
        placeholders = ", ".join(["%s"] * len(self.data))
        query = f"INSERT INTO {self.table_name} ({columns}) VALUES ({placeholders}) RETURNING *"

        with self.client._get_connection() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, list(self.data.values()))
                conn.commit()
                row = cur.fetchone()

                class Result:
                    def __init__(self, data):
                        self.data = [dict(data)] if data else []

                return Result(row)


class PostgresUpdate:
    """Update query builder"""

    def __init__(self, client: PostgresClient, table_name: str, data: dict, where: list):
        self.client = client
        self.table_name = table_name
        self.data = data
        self.where = where

    def execute(self):
        set_clause = ", ".join([f"{k} = %s" for k in self.data.keys()])
        query = f"UPDATE {self.table_name} SET {set_clause}"
        params = list(self.data.values())

        # Add WHERE
        if self.where:
            conditions = []
            for op, col, val in self.where:
                if op == "eq":
                    conditions.append(f"{col} = %s")
                    params.append(val)
            query += " WHERE " + " AND ".join(conditions)

        query += " RETURNING *"

        with self.client._get_connection() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, params)
                conn.commit()
                rows = cur.fetchall()

                class Result:
                    def __init__(self, data):
                        self.data = [dict(row) for row in data]

                return Result(rows)


class PostgresDelete:
    """Delete query builder"""

    def __init__(self, client: PostgresClient, table_name: str, where: list):
        self.client = client
        self.table_name = table_name
        self.where = where

    def execute(self):
        query = f"DELETE FROM {self.table_name}"
        params = []

        if self.where:
            conditions = []
            for op, col, val in self.where:
                if op == "eq":
                    conditions.append(f"{col} = %s")
                    params.append(val)
            query += " WHERE " + " AND ".join(conditions)

        with self.client._get_connection() as conn:
            with conn.cursor() as cur:
                cur.execute(query, params)
                conn.commit()

                class Result:
                    data = []

                return Result()


class PostgresUpsert:
    """Upsert query builder"""

    def __init__(self, client: PostgresClient, table_name: str, data: dict):
        self.client = client
        self.table_name = table_name
        self.data = data

    def execute(self):
        # Simple implementation - try insert, on conflict do nothing
        return PostgresInsert(self.client, self.table_name, self.data).execute()


class PostgresRPC:
    """RPC call wrapper"""

    def __init__(self, client: PostgresClient, function_name: str, params: dict = None):
        self.client = client
        self.function_name = function_name
        self.params = params or {}

    def execute(self):
        """Execute stored procedure"""
        placeholders = ", ".join([f"{k} => %s" for k in self.params.keys()])
        query = f"SELECT * FROM {self.function_name}({placeholders})"

        with self.client._get_connection() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, list(self.params.values()))
                rows = cur.fetchall()

