import logging
from typing import Optional, Any
import os

logger = logging.getLogger(__name__)

# Use local PostgreSQL as primary database
LOCAL_DB_URL = os.getenv("DATABASE_URL", "postgresql://rmi_user:rmi_secure_pass_2024@localhost:5432/rmi_db")

class DatabaseManager:
    """Manages database connections"""

    _supabase = None
    _postgres = None
    _redis = None

    @classmethod
    def get_supabase(cls):
        """Get or create database client (Supabase or local PostgreSQL)"""
        if cls._supabase is None:
            # Try Supabase first
            try:
                from supabase import create_client, Client
                from config.settings import settings

                if settings.SUPABASE_URL and settings.SUPABASE_KEY:
                    # Test the key format
                    if settings.SUPABASE_KEY.startswith("eyJ"):
                        cls._supabase = create_client(
                            settings.SUPABASE_URL,
                            settings.SUPABASE_KEY
                        )
                        logger.info("Supabase client initialized")
                    else:
                        logger.warning("Supabase key appears invalid (not JWT format), using local PostgreSQL")
                        cls._use_local_postgres()
                else:
                    logger.warning("Supabase credentials not configured, using local PostgreSQL")
                    cls._use_local_postgres()
            except ImportError:
                logger.warning("supabase package not installed, using local PostgreSQL")
                cls._use_local_postgres()
            except Exception as e:
                logger.error(f"Supabase connection error: {e}, using local PostgreSQL")
                cls._use_local_postgres()
        return cls._supabase

    @classmethod
    def _use_local_postgres(cls):
        """Use local PostgreSQL instead of Supabase"""
        try:
            from database.postgres_client import PostgresClient
            cls._supabase = PostgresClient(LOCAL_DB_URL)
            logger.info(f"Local PostgreSQL client initialized: {LOCAL_DB_URL}")
        except Exception as e:
            logger.error(f"Failed to initialize local PostgreSQL: {e}")
            # Fall back to mock
            cls._supabase = MockSupabaseClient()

    @classmethod
    def get_redis(cls):
        """Get or create Redis connection"""
        if cls._redis is None:
            try:
                import redis as redis_lib
                from config.settings import settings

                if settings.REDIS_URL:
                    cls._redis = redis_lib.from_url(
                        settings.REDIS_URL,
                        decode_responses=True
                    )
                    cls._redis.ping()
                    logger.info("Redis connection initialized")
            except ImportError:
                logger.warning("redis package not installed")
            except Exception as e:
                logger.warning(f"Redis connection error: {e}")
        return cls._redis

    @classmethod
    def close_connections(cls):
        """Close all database connections"""
        if cls._redis:
            try:
                cls._redis.close()
            except:
                pass
            cls._redis = None
            logger.info("Redis connection closed")
        cls._supabase = None


